import{c as e,Q as t,j as s,m as i}from"./chunks/framework.DVkeSyfh.js";const b=JSON.parse('{"title":"Database Optimization Script","description":"","frontmatter":{},"headers":[],"relativePath":"scripts/optimize-database.md","filePath":"scripts/optimize-database.md","lastUpdated":1780015851000}'),n={name:"scripts/optimize-database.md"};function p(o,a,r,l,d,c){return t(),s("div",null,[...a[0]||(a[0]=[i(`<h1 id="database-optimization-script" tabindex="-1">Database Optimization Script <a class="header-anchor" href="#database-optimization-script" aria-label="Permalink to &quot;Database Optimization Script&quot;">​</a></h1><p>Run this script with the project Python environment when possible:</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.\\.venv\\Scripts\\</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">python.exe</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> scripts\\optimize_database.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">help</span></span></code></pre></div><p>Optimizes a supported project SQLite database. The script recognizes the main library database and the Rhythm Lab label database by their marker tables, creates a backup, vacuums, analyzes, and verifies integrity. It does not migrate, repair, or adapt database schemas.</p><p>Use this script after large scan, reset, clear, relocation, analysis, labeling, or prediction churn if the SQLite file has grown or you want a fresh integrity check. It is not part of normal daily use and should not be used to fix schema or data problems.</p><p>Usage:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>python scripts\\optimize_database.py --db DB</span></span></code></pre></div><p>Example:</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python scripts\\optimize_database.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">db .\\</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">data</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">\\library.sqlite</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python scripts\\optimize_database.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">db tools\\rhythm</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">lab\\</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">data</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">\\rhythm_lab.sqlite</span></span></code></pre></div><p>This script writes to the database and creates a backup next to it. If the database is not recognized as either the main library database or Rhythm Lab database, the script prints an error and stops before creating a backup or modifying the database.</p><p>There is only one operating mode and no dry-run: every successful run validates basic support markers and integrity, makes a backup, and optimizes the file in place.</p><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><ol><li>Require the <code>--db</code> file to exist.</li><li>Run <code>PRAGMA integrity_check</code>; abort if the result is not <code>ok</code>.</li><li>Detect a supported database kind from marker tables: <ul><li>main library: <code>tracks</code> and <code>embeddings</code></li><li>Rhythm Lab: <code>classifier_profiles</code>, <code>classifier_labels</code>, <code>classifier_predictions</code>, and <code>classifier_training_checkpoints</code> Unknown SQLite files abort before the backup.</li></ul></li><li>Create an online SQLite backup named <code>&lt;db-name&gt;.bak-&lt;YYYYMMDD-HHMMSS&gt;</code> next to the database (a numeric suffix is added if that name already exists).</li><li>Set WAL journaling, then run <code>VACUUM</code>, <code>ANALYZE</code>, <code>PRAGMA optimize</code>, and a truncating WAL checkpoint.</li><li>Run <code>PRAGMA integrity_check</code> again; abort if the result is not <code>ok</code>.</li></ol><h2 id="output" tabindex="-1">Output <a class="header-anchor" href="#output" aria-label="Permalink to &quot;Output&quot;">​</a></h2><p>On success the script prints a short summary to standard output:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>database=&lt;resolved database path&gt;</span></span>
<span class="line"><span>database_kind=&lt;library|rhythm_lab&gt;</span></span>
<span class="line"><span>backup=&lt;backup file path&gt;</span></span>
<span class="line"><span>integrity_before=ok</span></span>
<span class="line"><span>integrity_after=ok</span></span>
<span class="line"><span>size_before=&lt;bytes&gt;</span></span>
<span class="line"><span>size_after=&lt;bytes&gt;</span></span></code></pre></div><p>The only file the script writes besides the optimized database is the backup <code>&lt;db-name&gt;.bak-&lt;timestamp&gt;</code>. There is no JSON, XLSX, or log report.</p><blockquote><p>Warning: this script is for recognized project databases only. It refuses to run on unrelated SQLite files, does not migrate schemas, and does not ask for confirmation before optimizing.</p></blockquote><p>Close the running app or Rhythm Lab before optimizing the same database so the backup, vacuum, and integrity check operate on a quiet file.</p>`,19)])])}const k=e(n,[["render",p]]);export{b as __pageData,k as default};
